import{_ as t,o as p,c as e,aj as i}from"./chunks/framework.DNJ2HNkG.js";const A=JSON.parse('{"title":"家庭网络升级指南【四】","description":"","frontmatter":{"title":"家庭网络升级指南【四】","date":"2023-12-12T21:16:18.000Z","category":"Home","tags":["网络"]},"headers":[],"relativePath":"posts/家庭网络升级指南【四】.md","filePath":"posts/家庭网络升级指南【四】.md","lastUpdated":1783008259000}'),r={name:"posts/家庭网络升级指南【四】.md"};function o(s,a,n,_,P,E){return p(),e("div",null,[...a[0]||(a[0]=[i('<p>距离上一次更新已经一年半了，这段时间也折腾了一些机器，整了不少花活，DIY了一些设备，还学了下SolidWorks玩了下3D打印，最近为了娃买了个小四居，重新装修了下，以后也能有个自己的小工作间小实验室，借着这个机会，也重新梳理下自己的需求，做了下减法，写个小总结。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E5%BA%AD%E7%BD%91%E7%BB%9C%E5%8D%87%E7%BA%A7%E6%8C%87%E5%8D%97%E3%80%90%E5%9B%9B%E3%80%91/1702390287774.png" alt="家庭服务器"></p><h2 id="_0x50-明确自己的需求" tabindex="-1">0x50 明确自己的需求 <a class="header-anchor" href="#_0x50-明确自己的需求" aria-label="Permalink to &quot;0x50 明确自己的需求&quot;">​</a></h2><p><strong>这个是最重要的，有明确的目标和需求才好做规划，想一出是一出最后就是不停的折腾，浪费了精力，浪费了时间，也浪费了金钱。</strong></p><p>怎么确定自己的需求呢？很简单，当前想做啥，今年想做啥，明年想做啥，目标越长远越好，能像国家的三年计划五年计划最好，这里我就随便举例几个需求。</p><p>1、家里拉2条宽带，希望双线备份或者链路聚合 2、家里物联网设备很多，希望能有独立的网段隔离 3、某些设备需要科学上网 4、需要NAS备份照片、视频、数据，需要公网访问或者内网穿透 5、需要跑一些虚拟机或者Docker用于PT下载、Home Assistant等等 6、儿童设备需要家长管理 7、wifi覆盖要无死角，要速度快，还要有访客wifi 8、家里有监控POE摄像头，有录像机 9、想用闲置宽带跑个PCDN、PT挣点水电费积分 10、局域网传输要快，至少2.5G或者10G</p><p>相信以上10个需求，能覆盖觉大多数人的需求了吧？</p><h3 id="_0x51-明确自己的预算" tabindex="-1">0x51 明确自己的预算 <a class="header-anchor" href="#_0x51-明确自己的预算" aria-label="Permalink to &quot;0x51 明确自己的预算&quot;">​</a></h3><p>万物皆有成本，巧妇难为无米之炊，既要也要还要都要不是做不到，是要付出其他的代价，比如时间、精力、人情等等。</p><p>前面10点需求，1K？5K？1W？2W？都能满足需求，不过穷有穷的玩法，富有富的做法，一分钱一分货，要么花钱省事，要么省钱费时间。如果自己管账，想清楚想明白就行，毕竟家庭网络是一家人共用，如果是媳妇管账，那就想好怎么说服媳妇能批这个预算，男人的爱好就这么点，总比在外面吃喝玩乐好吧？</p><p>当然，最好不要因为这点钱搞出家庭矛盾，完全不值得，机器哪有媳妇暖心。</p><h3 id="_0x52-敲定初步解决方案" tabindex="-1">0x52 敲定初步解决方案 <a class="header-anchor" href="#_0x52-敲定初步解决方案" aria-label="Permalink to &quot;0x52 敲定初步解决方案&quot;">​</a></h3><p>细化、拆解需求，写一个初步解决方案，选定要购买的设备型号，画出拓扑图。</p><p>1、肯定需要一台软路由做网络接入，考虑到有网段划分、科学上网的需求，单纯用mips或者arm的路由器性能不够，很难满足需求，所以这里考虑3种方案： A、mips/arm小包转发性能好，用RouterOS、LEDE、iKuai作为拨号和策略路由，后面接低性能x86路由跑科学上网【mips/arm不是不能跑科学上网插件，只不过性能实在难以恭维】 B、性能好一点的x86路由，跑PVE或者ESXi，虚拟出RouterOS、LEDE、iKuai，这里推荐J4125+i226的组合，10w功耗性能出众价格便宜 C、用ITX主板+35W低压CPU+PCIE万兆网卡 DIY出一台万兆软路由，跑PVE或者ESXi，虚拟出RouterOS、LEDE、iKuai，如果对体积没要求，还可以用接口更多的mATX主板接入更多的硬盘，直接虚拟出群晖或者QNAP、unraid之类的</p><p>2、网段隔离这个需求很简单，不论那个软路由OS都支持，交换机和AP能支持vlan就行，如果不支持也能通过多网段多网关来实现这个目标</p><p>3、科学上网在1里面已经顺带解决了</p><p>4、NAS的方案非常多，不管是买商业化成品NAS，还是自己DIY都问题不大，公网IP访问和内网穿透也都在1里面解决</p><p>5、虚拟机和Docker，这个要看具体需求，如果需求很少，比如就PT和HA，1的planB就可以满足，如果跑的多，建议planC</p><p>6、家庭管理也在1里面解决，但需要注意的是这个功能比较吃CPU，对软路由性能要求高，不过如果用路由器可能内置这部分功能</p><p>7、wifi覆盖现在wifi7已经出来了，但国内6G频段只给了低频一部分，全靠MLO实际意义不大，所以wifi6足够大部分人使用，wifi5也不算太落后，要求不高也能用。如果房子不大，一个信号强一点的路由器直接覆盖就行了，如果房子大或者承重墙阻隔多，不管是Mesh还是AC+AP的组合都可以，不过Mesh的回程偶尔会出bug，能用AC+AP方案还是尽量用这套，个别四角可以考虑用电力猫来补点</p><p>8、POE设备用POE交换机就行，当前千兆POE交换机已经白菜价，2.5G螃蟹方案的带管理的交换机也不贵，万兆POE交换机也贵不了太多，根据摄像头数量、功率选定POE交换机即可。注意，如果采用AC+AP方案且AP采用POE供电，这部分功耗别忘了</p><p>9、跑PCDN或者PT，单独划一个网络做好隔离和限制就行，另外因为连接数很多，路由器性能和猫的性能都有要求，这部分需要注意</p><p>10、现在2.5G已经普及了，10G成本也不高，如果新装修能埋光纤，直接埋上铠装双LC光纤，再加个超五或者六类网线，几年内都都不会过时，如果没法预埋光纤也不想走明线墙角线之类，检查下当前墙里埋的网线质量，没啥问题的话跑电口10G问题也不大</p><p>到这里，初步解决方案其实已经有了：</p><p>1、换个好点的猫或者猫棒 2、搞个性能好点的软路由，最低要J4125+i226档次的，J1900、3865U之类的古董就不建议上了，除非真的差这一两百预算。系统跑ESXi/PVE，虚拟出软路由OS和HA等虚拟机应用，如果性能很强硬盘很多，可以再虚拟个NAS进去做All in Boom 3、交换机按需求看搞万兆还是2.5G 4、WIFI覆盖可以考虑华硕、网件、华为、小米、TP-Link等Mesh路由，也可以考虑TP-Link/H3C/iKuai/Router/Ubnt/Aruba等品牌的AC+AP系统，这里有很多三方刷机OS可以考虑，当然里面也有不少坑，后面会讲 5、</p>',25)])])}const m=t(r,[["render",o]]);export{A as __pageData,m as default};
